mapper.select:
SELECT * FROM (
SELECT
d.disposal_Id as disposalId, f.foodMaterialName, fc.foodCategory, f.foodMaterialType,
d.disposalCountAll, d.disposalPrice, d.disposalDate, r.reason,
ROW_NUMBER() OVER (ORDER BY d.disposal_Id DESC) as rn
FROM DISPOSALS d
JOIN FOODM f ON d.foodMaterial_Id = f.foodMaterial_Id
JOIN FOODC fc ON f.foodCategory_Id = fc.foodCategory_Id
JOIN REASON r ON d.reason_Id = r.reason_Id
WHERE f.bId = #{bId}

	AND fc.foodCategory = #{category}


	AND r.reason = #{reason}

) WHERE rn BETWEEN #{start} AND #{end}

SELECT COUNT(*) FROM DISPOSALS d JOIN FOODM f ON d.foodMaterial_Id = f.foodMaterial_Id JOIN FOODC fc ON f.foodCategory_Id = fc.foodCategory_Id JOIN REASON r ON d.reason_Id = r.reason_Id WHERE f.BID = #{bId}
AND fc.foodCategory = #{category}
AND r.reason = #{reason}

SELECT COUNT(*) FROM DISPOSALS d JOIN FOODM f ON d.foodMaterial_Id = f.foodMaterial_Id JOIN FOODC fc ON f.foodCategory_Id = fc.foodCategory_Id JOIN REASON r ON d.reason_Id = r.reason_Id WHERE f.BID = #{bId}
AND fc.foodCategory = #{category}
AND r.reason = #{reason}

SELECT * FROM (
SELECT d.*, f.foodMaterialName, fc.foodCategory, r.reason, ROWNUM as rn
FROM DISPOSALS d
JOIN FOODM f ON d.foodMaterial_Id = f.foodMaterial_Id
JOIN FOODC fc ON f.foodCategory_Id = fc.foodCategory_Id
JOIN REASON r ON d.reason_Id = r.reason_Id
WHERE f.bId = #{bId}
ORDER BY d.disposal_Id DESC
) WHERE rn BETWEEN #{start} AND #{end}
